var e=[{id:`L2_1`,type:`dialog`,speaker:`LENA_COFFIN_NULL_NULL`,text:{KOREA:`어떤 고유 파장을 가진 카운터가 함께 하느냐가, 때론 전장의 양상을 크게 바꾸기도 합니다.`,JPN:`どのような固有波長を持ったカウンターが共にするのかが、たまには戦場の様相を大きく替えたりします。`,ENG:`Sometimes, the tide of battle can change based on which unique wavelength your ally Counters have.`,TWN:`要是幾個波長獨特的制裁者並肩作戰的話，他們有時候可以改變戰局。`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LENA_COFFIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`쉽게 말하자면, 게임에서의 이로운 버프 같은 거죠.`,JPN:`容易に言おうとすると、ゲームでのよいバフのようなことですよ。`,ENG:`So simply put, it's like getting a buff in a game.`,TWN:`簡單來說，就像遊戲中的增益效果一樣。`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`LENA_COFFIN_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L6_1`,type:`dialog`,speaker:`LENA_COFFIN_NULL_NULL`,text:{KOREA:`네? 그, 그렇게 되나요?`,JPN:`はい?彼、そのようになるの?`,ENG:`Huh? I-I suppose so?`,TWN:`哦？真、真的會這樣嗎？`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`LENA_COFFIN_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L8_1`,type:`dialog`,speaker:`LENA_COFFIN_NULL_NULL`,text:{KOREA:`아무튼 이번 시뮬레이팅에선 서윤 소대장님이 가진 고유파장이 작전의 성공여부에 가장 큰 작용을 했어요.`,JPN:`とにかく今回シミュルレーティングではソニア小隊長様が持った固有波長が作戦の成否に最も大きい作用をしました。`,ENG:`Anyway, Commander Seo Yoon, your unique wavelength played a large role in leading this simulation mission to a success.`,TWN:`總而言之，在這次模擬中徐芸隊長的固有波長對作戰的成敗至關重要。`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LENA_COFFIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`LENA_COFFIN_NULL_NULL`,text:{KOREA:`분명 실전에서도 많은 도움이 될 겁니다.`,JPN:`確かに実戦でも多くの助けになるでしょう。`,ENG:`I'm sure it will be very helpful in real operations as well.`,TWN:`在實戰中肯定會有所幫助。`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LENA_COFFIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`저희야, 이렇게 믿고 써 주시니 감사할 따름이죠.`,JPN:`私どもよ、このように信じて使ってくれるから感謝するだけです。`,ENG:`We're just glad to know that you believe in us.`,TWN:`非常感謝你們如此信任和重用我們。`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};